class Solution {
    public int repeatedStringMatch(String a, String b) {
        int count = 0;
        StringBuilder sb = new StringBuilder(a);
        while (sb.length() <= b.length()) {
            if (sb.toString().contains(b)) {
                return count + 1;
            }
            sb.append(a);
            count++;
            if (sb.length() > b.length() * 2) {
                return -1;
            }
        }
        return -1;
    }
}
```

